class DebugParser:
    def __init__(self, expression):
        self.expression = expression.strip()
        self.pos = 0
        self.length = len(self.expression)

    def parse(self):
        node = self._parse_expression()
        return node

    def _parse_expression(self):
        print("  _parse_expression, pos:", self.pos)
        return self._parse_term()

    def _parse_term(self):
        print("  _parse_term, pos:", self.pos)
        left = self._parse_factor()
        return left

    def _parse_factor(self):
        print("  _parse_factor, pos:", self.pos)
        left = self._parse_primary()
        return left

    def _parse_primary(self):
        print("  _parse_primary, pos:", self.pos)
        if self.pos >= self.length:
            raise ValueError("Unexpected end of expression")

        char = self.expression[self.pos]
        print(f"    char at pos {self.pos}: {repr(char)}")

        if char == "(":
            self.pos += 1
            node = self._parse_expression()
            print(
                f"    after _parse_expression, pos: {self.pos}, char: {repr(self.expression[self.pos] if self.pos < self.length else 'EOF')}"
            )
            if self.pos >= self.length or self.expression[self.pos] != ")":
                raise ValueError("Unmatched parenthesis")
            self.pos += 1
            return node

        raise ValueError(f"Unexpected character at position {self.pos}: {char}")


parser = DebugParser("((2+3)*4)-6/2")
result = parser.parse()
print("Result:", result)

class ASTNode:
    def __init__(self, type, value=None, op=None, left=None, right=None, operand=None):
        self.type = type
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand

    def __repr__(self):
        if self.type == "number":
            return "Number(" + str(self.value) + ")"
        elif self.type == "binop":
            return (
                "BinOp("
                + str(self.op)
                + ", "
                + str(self.left)
                + ", "
                + str(self.right)
                + ")"
            )
        elif self.type == "unary":
            return "Unary(" + str(self.op) + ", " + str(self.operand) + ")"


class ExpressionParser:
    def __init__(self, expression):
        self.expression = expression.strip()
        self.pos = 0
        self.length = len(self.expression)
        if not self.expression:
            raise ValueError("Empty expression")

    def parse(self):
        node = self._parse_expression()
        self._skip_whitespace()
        if self.pos != self.length:
            raise ValueError(
                f"Unexpected character at position {self.pos}: {self.expression[self.pos]}"
            )
        return node

    def _skip_whitespace(self):
        while self.pos < self.length and self.expression[self.pos].isspace():
            self.pos += 1

    def _parse_expression(self):
        self._skip_whitespace()
        return self._parse_term()

    def _parse_term(self):
        left = self._parse_factor()
        while self.pos < self.length:
            self._skip_whitespace()
            if self.expression[self.pos] in "+-":
                op = self.expression[self.pos]
                self.pos += 1
                right = self._parse_term()
                left = ASTNode("binop", op=op, left=left, right=right)
            else:
                break
        return left

    def _parse_factor(self):
        left = self._parse_primary()
        while self.pos < self.length:
            self._skip_whitespace()
            if self.expression[self.pos] in "*/":
                op = self.expression[self.pos]
                self.pos += 1
                right = self._parse_factor()
                left = ASTNode("binop", op=op, left=left, right=right)
            else:
                break
        return left

    def _parse_primary(self):
        if self.pos >= self.length:
            raise ValueError("Unexpected end of expression")

        if self.expression[self.pos] == "(":
            self.pos += 1
            self._skip_whitespace()
            node = self._parse_expression()
            if self.pos >= self.length or self.expression[self.pos] != ")":
                raise ValueError("Unmatched parenthesis")
            self.pos += 1
            return node

        if self.expression[self.pos] == "-":
            self.pos += 1
            operand = self._parse_primary()
            return ASTNode("unary", op="-", operand=operand)

        return self._parse_number()

    def _parse_number(self):
        start = self.pos
        self._skip_whitespace()
        if start >= self.length:
            raise ValueError(f"Unexpected end of expression")
        if not self.expression[start].isdigit() and self.expression[start] != ".":
            raise ValueError(
                f"Unexpected character at position {self.pos}: {self.expression[self.pos]}"
            )

        dot_count = 0
        while self.pos < self.length:
            char = self.expression[self.pos]
            if char.isdigit():
                self.pos += 1
            elif char == ".":
                if dot_count >= 1:
                    raise ValueError(
                        f"Multiple decimal points in number at position {self.pos}"
                    )
                dot_count += 1
                self.pos += 1
            else:
                break

        if self.pos == start:
            raise ValueError(f"Invalid number at position {self.pos}")

        num_str = self.expression[start : self.pos]
        try:
            num = float(num_str)
        except ValueError:
            raise ValueError(f"Invalid number: {num_str}")

        return ASTNode("number", value=num)


def parse(expression: str) -> ASTNode:
    parser = ExpressionParser(expression)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        return float(node.value)
    elif node.type == "binop":
        left = evaluate(node.left)
        right = evaluate(node.right)
        if node.op == "+":
            return left + right
        elif node.op == "-":
            return left - right
        elif node.op == "*":
            return left * right
        elif node.op == "/":
            if right == 0:
                raise ZeroDivisionError("Division by zero")
            return left / right
        else:
            raise ValueError(f"Unknown operator: {node.op}")
    elif node.type == "unary":
        operand = evaluate(node.operand)
        if node.op == "-":
            return -operand
        else:
            raise ValueError(f"Unknown unary operator: {node.op}")
    else:
        raise ValueError(f"Unknown node type: {node.type}")
